// Parse RSS XML to structured items
function parseRSS(xmlText, sourceName) {
  const items = [];
  const sevenDaysAgo = new Date(Date.now() - 7 * 24 * 60 * 60 * 1000);

  // Extract <item> blocks
  const itemMatches = xmlText.match(/<item[^>]*>([\s\S]*?)<\/item>/gi) || [];

  for (const itemXml of itemMatches.slice(0, 15)) {
    const getTag = (tag) => {
      const match = itemXml.match(new RegExp(`<${tag}(?:[^>]*)>(?:<!\\[CDATA\\[)?([\\s\\S]*?)(?:\\]\\]>)?<\/${tag}>`, 'i'));
      return match ? match[1].trim().replace(/<[^>]+>/g, '').replace(/&amp;/g, '&').replace(/&lt;/g, '<').replace(/&gt;/g, '>').replace(/&quot;/g, '"').replace(/&#39;/g, "'") : '';
    };

    const title = getTag('title');
    const link = getTag('link') || itemXml.match(/<link>([^<]+)<\/link>/i)?.[1] || '';
    const pubDate = getTag('pubDate') || getTag('dc:date') || '';
    const description = getTag('description').substring(0, 400);
    const category = getTag('category');

    if (!title) continue;

    // Date filter - last 7 days
    let itemDate = null;
    if (pubDate) {
      try { itemDate = new Date(pubDate); } catch(e) {}
    }
    if (itemDate && !isNaN(itemDate) && itemDate < sevenDaysAgo) continue;

    // Keywords for relevance scoring
    const text = (title + ' ' + description + ' ' + category).toLowerCase();
    let relevanceScore = 0;
    const secKeywords = ['vulnerability', 'cve', 'exploit', 'malware', 'ransomware', 'breach', 'attack', 'zero-day', 'zero day', 'patch', 'critical', 'rce', 'backdoor', 'botnet', 'phishing', 'threat', 'security', 'ai ', 'artificial intelligence', 'llm', 'cyber'];
    for (const kw of secKeywords) {
      if (text.includes(kw)) relevanceScore += (kw.length > 6 ? 2 : 1);
    }

    items.push({
      source: sourceName,
      title,
      link: link.trim(),
      pubDate: itemDate ? itemDate.toISOString() : pubDate,
      description,
      category,
      relevanceScore
    });
  }

  return items.sort((a, b) => b.relevanceScore - a.relevanceScore).slice(0, 8);
}

const inputs = $input.all();
const allNewsItems = [];
const sourceNames = [
  'The Hacker News', 'BleepingComputer', 'Krebs on Security',
  'Dark Reading', 'CIS Security', 'SecurityWeek',
  'Unit42 Palo Alto', 'SANS ISC', 'Microsoft Security'
];

// The inputs arrive as separate items from the merge node
for (let i = 0; i < inputs.length; i++) {
  const item = inputs[i];
  const xmlData = item.json.data || item.json.body || (typeof item.json === 'string' ? item.json : JSON.stringify(item.json));
  const sourceName = sourceNames[i] || `Feed ${i+1}`;

  if (typeof xmlData === 'string' && xmlData.includes('<item')) {
    const parsed = parseRSS(xmlData, sourceName);
    allNewsItems.push(...parsed);
  }
}

// Sort by relevance and deduplicate by title similarity
allNewsItems.sort((a, b) => b.relevanceScore - a.relevanceScore);

const seen = new Set();
const deduped = [];
for (const item of allNewsItems) {
  const key = item.title.toLowerCase().replace(/[^a-z0-9]/g, '').substring(0, 40);
  if (!seen.has(key)) {
    seen.add(key);
    deduped.push(item);
  }
}

// Separate AI-related news
const aiNews = deduped.filter(i => {
  const t = (i.title + ' ' + i.description).toLowerCase();
  return t.includes(' ai ') || t.includes('artificial intelligence') || t.includes('machine learning') || t.includes('llm') || t.includes('generative') || t.includes('chatgpt') || t.includes('openai') || t.includes('deepseek');
}).slice(0, 6);

const secNews = deduped.filter(i => !aiNews.includes(i)).slice(0, 12);

return [{ json: { securityNews: secNews, aiNews: aiNews, totalItems: deduped.length } }];

// Process NVD CVE data and EPSS scores
const inputs = $input.all();

// Expect: [0]=critical CVEs, [1]=high CVEs, [2]=EPSS, [3]=CISA KEV
const criticalData = inputs[0]?.json || {};
const highData = inputs[1]?.json || {};
const epssData = inputs[2]?.json || {};
const kevData = inputs[3]?.json || {};

// Process NVD CVEs
function processCVEs(nvdResponse, maxItems = 15) {
  const vulns = nvdResponse.vulnerabilities || [];
  return vulns.slice(0, maxItems).map(v => {
    const cve = v.cve || {};
    const metrics = cve.metrics || {};
    const cvssV31 = metrics.cvssMetricV31?.[0]?.cvssData;
    const cvssV30 = metrics.cvssMetricV30?.[0]?.cvssData;
    const cvssData = cvssV31 || cvssV30;

    const descriptions = cve.descriptions || [];
    const enDesc = descriptions.find(d => d.lang === 'en')?.value || 'No description available.';

    const references = (cve.references || []).slice(0, 3).map(r => r.url);

    const weaknesses = (cve.weaknesses || []).flatMap(w => w.description || []).map(d => d.value).filter(Boolean).slice(0, 2);

    return {
      id: cve.id || 'N/A',
      published: cve.published || '',
      lastModified: cve.lastModified || '',
      description: enDesc.substring(0, 500),
      severity: cvssData?.baseSeverity || 'UNKNOWN',
      baseScore: cvssData?.baseScore || 0,
      attackVector: cvssData?.attackVector || '',
      attackComplexity: cvssData?.attackComplexity || '',
      privilegesRequired: cvssData?.privilegesRequired || '',
      userInteraction: cvssData?.userInteraction || '',
      scope: cvssData?.scope || '',
      confidentialityImpact: cvssData?.confidentialityImpact || '',
      vectorString: cvssData?.vectorString || '',
      weaknesses: weaknesses,
      references: references
    };
  });
}

// EPSS top scores
const epssItems = (epssData.data || []).slice(0, 15).map(e => ({
  cveId: e.cve,
  epssScore: parseFloat(e.epss || 0),
  percentile: parseFloat(e.percentile || 0),
  date: e.date
}));

// CISA KEV - recently added (last 7 days)
const sevenDaysAgo = new Date(Date.now() - 7 * 24 * 60 * 60 * 1000);
const kevVulns = (kevData.vulnerabilities || []).filter(v => {
  if (!v.dateAdded) return false;
  try { return new Date(v.dateAdded) >= sevenDaysAgo; } catch(e) { return false; }
}).map(v => ({
  cveId: v.cveID,
  vendorProject: v.vendorProject,
  product: v.product,
  vulnerabilityName: v.vulnerabilityName,
  dateAdded: v.dateAdded,
  shortDescription: (v.shortDescription || '').substring(0, 300),
  requiredAction: v.requiredAction,
  dueDate: v.dueDate
}));

const criticalCVEs = processCVEs(criticalData, 10);
const highCVEs = processCVEs(highData, 8);

// Merge all CVEs and sort by score
const allCVEs = [...criticalCVEs, ...highCVEs].sort((a, b) => b.baseScore - a.baseScore);

// Cross-reference EPSS with CVE details
const epssWithDetails = epssItems.map(e => {
  const detail = allCVEs.find(c => c.id === e.cveId);
  return {
    ...e,
    severity: detail?.severity || 'UNKNOWN',
    baseScore: detail?.baseScore || null,
    description: detail?.description || 'Fetch from NVD for details.',
    attackVector: detail?.attackVector || ''
  };
});

return [{
  json: {
    criticalCVEs: criticalCVEs.slice(0, 8),
    highCVEs: highCVEs.slice(0, 5),
    topEPSS: epssWithDetails.slice(0, 10),
    kevAdded: kevVulns.slice(0, 8),
    stats: {
      totalCritical: criticalData.totalResults || 0,
      totalHigh: highData.totalResults || 0,
      kevTotal: kevData.count || 0,
      kevNewThisWeek: kevVulns.length
    }
  }
}];

// Log execution result
const input = $input.all()[0]?.json || {};
console.log('✅ Weekly Threat Intel email sent successfully');
console.log('Subject:', input.subject);
console.log('HTML length:', input.htmlReport?.length || 0);
return [{ json: { status: 'sent', timestamp: new Date().toISOString(), subject: input.subject } }];

// Build the comprehensive prompt for Ollama LLM
const allInputs = $input.all();
const cveData = allInputs[0]?.json || {};
const newsData = allInputs[1]?.json || {};

const weekStart = new Date(Date.now() - 7 * 24 * 60 * 60 * 1000).toLocaleDateString('pt-PT', {day:'2-digit', month:'2-digit', year:'numeric'});
const weekEnd = new Date().toLocaleDateString('pt-PT', {day:'2-digit', month:'2-digit', year:'numeric'});

// Format CVE data for prompt
const formatCVEs = (cves) => cves.map(c => 
  `- ${c.id} | CVSS: ${c.baseScore} (${c.severity}) | AV:${c.attackVector} | ${c.description.substring(0,200)}`
).join('\n');

const formatEPSS = (items) => items.map(e =>
  `- ${e.cveId} | EPSS: ${(e.epssScore*100).toFixed(2)}% (${(e.percentile*100).toFixed(1)}th percentile) | ${e.description?.substring(0,150) || 'See NVD for details'}`
).join('\n');

const formatKEV = (items) => items.map(k =>
  `- ${k.cveId} | ${k.vendorProject} ${k.product} | ${k.vulnerabilityName} | Due: ${k.dueDate}`
).join('\n');

const formatNews = (items) => items.map(n =>
  `- [${n.source}] ${n.title} | ${n.description?.substring(0,200)}`
).join('\n');

const prompt = `És um especialista sénior em cibersegurança e threat intelligence. Analisa os dados da semana de ${weekStart} a ${weekEnd} e cria um relatório executivo semanal em PORTUGUÊS de Portugal, em formato HTML.

## DADOS PARA ANÁLISE:

### CVEs CRÍTICOS DA SEMANA (NVD):
${formatCVEs(cveData.criticalCVEs || [])}

### CVEs ELEVADOS DA SEMANA (NVD):
${formatCVEs(cveData.highCVEs || [])}

### TOP CVEs POR EPSS (maior probabilidade de exploração):
${formatEPSS(cveData.topEPSS || [])}

### CISA KEV - ADICIONADOS ESTA SEMANA (exploração ativa confirmada):
${formatKEV(cveData.kevAdded || [])}

### NOTÍCIAS DE CIBERSEGURANÇA:
${formatNews(newsData.securityNews || [])}

### NOTÍCIAS IA & SEGURANÇA:
${formatNews(newsData.aiNews || [])}

### ESTATÍSTICAS:
- Total CVEs Críticos publicados: ${cveData.stats?.totalCritical || 0}
- Total CVEs Elevados publicados: ${cveData.stats?.totalHigh || 0}
- CVEs adicionados ao CISA KEV esta semana: ${cveData.stats?.kevNewThisWeek || 0}

## INSTRUÇÕES PARA O RELATÓRIO HTML:

Cria um email HTML profissional com as seguintes secções:

1. **CABEÇALHO EXECUTIVO** - Resumo de 2-3 frases do nível de ameaça da semana, com avaliação geral (Baixo/Médio/Alto/Crítico)

2. **⚠️ AÇÃO IMEDIATA REQUERIDA** - CVEs no CISA KEV (exploração ativa). Para cada um: identificar sistemas afetados, impacto potencial e ação de remediação recomendada.

3. **🔴 CVEs CRÍTICOS DA SEMANA** - Top 6 CVEs mais importantes. Para cada um: ID, score CVSS, vetor de ataque, sistemas afetados, impacto, e recomendação.

4. **📊 TOP 8 CVEs POR EPSS** - Os com maior probabilidade de exploração ativa. Explica por que o EPSS é relevante e o que significa cada score.

5. **📰 NOTÍCIAS DE CIBERSEGURANÇA** - Top 8 notícias mais relevantes, com contexto e impacto potencial para organizações.

6. **🤖 IA & CIBERSEGURANÇA** - Notícias sobre IA aplicada a ataques, defesa ou novos riscos.

7. **💡 RECOMENDAÇÕES DA SEMANA** - 3-5 recomendações práticas priorizadas para equipas de segurança.

8. **📈 TENDÊNCIAS** - Padrões observados nos ataques e vulnerabilidades desta semana.

USA este template HTML:
- Background: #0d1117 (dark)
- Texto principal: #e6edf3
- Acentos: #f0883e (laranja para crítico), #3fb950 (verde para OK), #58a6ff (azul para info)
- Cards com border-radius: 8px, background: #161b22
- Tabelas para CVEs com headers escuros
- Badges coloridos por severidade: CRÍTICO=#da3633, ELEVADO=#d29922, MÉDIO=#1f6feb
- Fonte: system-ui, -apple-system, monospace para CVE IDs
- SEM links externos de imagens, CSS inline apenas
- Total: email completo, bem formatado, profissional

Resposta APENAS com o HTML capaz de ser lido no corpo do email, e sem mais nada antes ou depois.`;

return [{
  json: {
    prompt,
    cveData,
    newsData,
    weekStart,
    weekEnd,
    stats: cveData.stats
  }
}];

